INSERT INTO `v1_48f152cac8adc0ccaef4d79f469e5f9bb09c060e2c8584c993943c5f10d400d2` VALUES (0, 0, "あはは！\n今の聞いた？　にいちゃん！\nキョウカはピーマン苦手だもんねー？", 0, 1, 11, 7, 503, 503077, 0, 100411);
